"""Autogenerate directive scoping (#1427).

Lives outside ``env.py`` because env.py executes only under the alembic context
(it reads ``context.config`` at import time) and cannot be imported by tests —
the same rationale as ``framework_tables.include_object``. This module imports
only ``alembic.operations.ops`` (safe outside an alembic run), so the scoping
logic is unit-testable in isolation.
"""

from typing import Any

from alembic.operations import ops as alembic_ops


def scope_upgrade_to_additive(upgrade_ops: Any) -> list[str]:
    """Strip data-destructive ops from an autogenerated upgrade, in place.

    Removes ``DropTableOp`` / ``DropColumnOp`` / ``AlterColumnOp`` — the ops that
    drop a live column, drop a table, or destructively rewrite a column's type.
    Autogenerate diffs *generated-metadata vs live-DB*, so a Dazzle type-mapping
    mismatch (e.g. a project's hand-authored ``text`` PK vs the DSL's ``uuid``) or
    any schema drift otherwise becomes a whole-schema ``text→uuid`` rewrite + column
    drops. Scoping to additive ops (CREATE TABLE / ADD COLUMN / new indexes &
    constraints) makes a routine ``db revision`` structurally non-destructive;
    genuine destructive changes are hand-authored.

    Returns a human-readable description of every dropped op so the caller can log
    what was suppressed — never silent (an unlogged drop reads as "nothing to do").
    """
    dropped: list[str] = []
    kept: list[Any] = []
    for op in upgrade_ops.ops:
        if isinstance(op, alembic_ops.DropTableOp):
            dropped.append(f"drop_table {op.table_name}")
            continue
        if isinstance(op, alembic_ops.ModifyTableOps):
            sub_kept: list[Any] = []
            for sub in op.ops:
                if isinstance(sub, alembic_ops.DropColumnOp):
                    dropped.append(f"drop_column {op.table_name}.{sub.column_name}")
                    continue
                if isinstance(sub, alembic_ops.AlterColumnOp):
                    dropped.append(f"alter_column {op.table_name}.{sub.column_name}")
                    continue
                sub_kept.append(sub)
            if not sub_kept:
                continue  # the whole per-table modify was destructive — drop it
            op.ops = sub_kept
            kept.append(op)
            continue
        kept.append(op)
    upgrade_ops.ops = kept
    return dropped
